Object.keys(TERMS_LANGS).forEach(function (lang) {
  if (LANGS[lang]) {
    Object.assign(LANGS[lang], TERMS_LANGS[lang]);
  }
});

(function () {
  var baseSetLang = setLang;
  setLang = function (lang) {
    baseSetLang(lang);
    if (window.location.pathname.indexOf("terms.html") === -1) return;
    var dict = LANGS[lang];
    if (!dict) return;

    var subtitle = document.querySelector(".page-header .subtitle");
    if (subtitle && dict.tos_subtitle) subtitle.textContent = dict.tos_subtitle;

    if (dict.tos_meta_title) {
      document.title = dict.tos_meta_title;
      var ogTitle = document.querySelector('meta[property="og:title"]');
      if (ogTitle) ogTitle.setAttribute("content", dict.tos_meta_title);
      var twTitle = document.querySelector('meta[name="twitter:title"]');
      if (twTitle) twTitle.setAttribute("content", dict.tos_meta_title);
    }

    if (dict.tos_meta_description) {
      var meta = document.querySelector('meta[name="description"]');
      if (meta) meta.setAttribute("content", dict.tos_meta_description);
      var ogDesc = document.querySelector('meta[property="og:description"]');
      if (ogDesc) ogDesc.setAttribute("content", dict.tos_meta_description);
      var twDesc = document.querySelector('meta[name="twitter:description"]');
      if (twDesc) twDesc.setAttribute("content", dict.tos_meta_description);
    }
  };
})();
